proof fn phi_1_empty_interp_aux_external_body(d: Directory, i: nat)
    requires
        d.inv(),
        d.empty(),
    ensures
        d.interp_aux(i) === Map::empty(),
{
    d.lemma_empty_implies_interp_aux_empty(i);
}

proof fn phi_2_empty_interp_dom_external_body(d: Directory)
    requires
        d.inv(),
        d.empty(),
    ensures
        d.interp().dom() === Set::empty(),
{
    d.lemma_empty_implies_interp_empty();
}

proof fn phi_3_empty_interp_aux_any_start(d: Directory, i: nat)
    requires
        d.inv(),
        d.empty(),
        i > d.entries.len(),
    ensures
        d.interp_aux(i) === Map::empty(),
{
    d.lemma_empty_implies_interp_aux_empty(i);
}
